import{_ as l,o as n,c as s,b as t}from"./chunks/plugin-vue_export-helper.CrIAyUQY.js";const f=JSON.parse('{"title":"О фрустрации","description":"","frontmatter":{"title":"О фрустрации","date":"2022-10-16T00:00:00.000Z"},"headers":[],"relativePath":"posts/2022-10-16-frustration.md","filePath":"posts/2022-10-16-frustration.md"}'),o={name:"posts/2022-10-16-frustration.md"};function r(a,e,p,u,i,c){return n(),s("div",null,[...e[0]||(e[0]=[t("blockquote",null,[t("p",null,"Если после каждого падения ты находишь в себе силы подняться, то скорее всего ты - синусоида.")],-1),t("p",null,"Мотивом сменить место жительства, работу, закончить старые и начать новые отношения всегда является ожидание чего-то лучшего, большего и вкусного. Вдоволь нафрустрировавшись очередным несоответствием желаемого и действительного, я выработал в себе привычку адаптироваться.",-1),t("p",null,"Адаптация происходит постепенно.",-1),t("p",null,"Во-первых, правильные вопросы. Примеры неправильных вопросов - почему все так плохо? За что?! Где этому конец? и так далее. Примеры правильных вопросов - Что я могу сделать в сложившейся ситуации чтобы стало лучше чем было и по ходу получать удовольствие от процесса? Какое решение мне нужно принять чтобы перестать беспокоиться и начать жить и радоваться каждому мгновению? и так далее.",-1),t("p",null,"Хороший вопрос от плохого отличается тем, что меняет фокус восприятия в сторону изменения ситуации, а не заставляет копаться в прошлом и анализировать.",-1),t("p",null,"Во-вторых, внутреннее состояние. Каждое мое утро начинается с поиска и воссоединения с собой. Не скажу что это легко, но двигаясь в эту сторону рано или поздно будет результат в виде неописуемого и непередаваемого восторга жизни. Всякий раз это по-разному. Снаружи я могу все так же суетиться или механически куда-то идти, но в процессе вслушивания вглубь себя, рано или поздно я нахожу этот пульт внутреннего управления.",-1),t("p",null,'В-третьих, осознание себя в ситуации. К ситуационному мышлению я пришел своим умом, но потом узнал, что это довольно продвинутый способ мышления. У каждой ситуации есть начало и есть конец и они перетекают друг в друга. Осознание себя не только в пространстве, но и в ситуации, делают жизнь более полной и насыщенной ситуациями. Но насыщение происходит изнутри меня ответом на вопрос "Чем я наполняю эту ситуацию?" Таким образом возникает резонанс и причинно-следственный альянс состояние-ситуация.',-1),t("p",null,"Адаптация через резонанс видится мне более органичной чем механическое выстраивание отношений с миром и людьми через ярлыки и метафоры.",-1)])])}const _=l(o,[["render",r]]);export{f as __pageData,_ as default};
